{
  "name": "money-transfer-saga",
  "version": "1.0.0",
  "description": "Temporal Money Transfer Saga with compensation in TypeScript",
  "main": "lib/client.js",
  "scripts": {
    "build": "tsc --build",
    "start": "npm run build && node lib/run.js"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.8",
    "@temporalio/client": "^1.11.8",
    "@temporalio/worker": "^1.11.8",
    "@temporalio/workflow": "^1.11.8"
  },
  "devDependencies": {
    "typescript": "^5.4.5",
    "@tsconfig/node18": "^18.2.4"
  }
}

import { proxyActivities, ActivityFailure, ApplicationFailure } from '@temporalio/workflow';
import type * as activities from './activities';

// Proxy for withdraw and refund: generous retries are fine
const { withdraw, refund } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
  retry: {
    maximumAttempts: 3,
  },
});

// Proxy for deposit: limit attempts so the failure path terminates quickly
const { deposit } = proxyActivities<typeof activities>({
  startToCloseTimeout: '30 seconds',
  retry: {
    maximumAttempts: 1,
  },
});

export interface TransferInput {
  fromAccount: string;
  toAccount: string;
  amount: number;
}

/**
 * MoneyTransfer saga workflow.
 *
 * Happy path  → withdraw → deposit → COMPLETED
 * Failure path → withdraw → deposit (fails) → refund → re-throw → FAILED
 */
export async function MoneyTransfer(input: TransferInput): Promise<void> {
  const { fromAccount, toAccount, amount } = input;

  // Step 1: debit the source account
  await withdraw(fromAccount, amount);

  // Step 2: credit the destination account; compensate on failure
  try {
    await deposit(toAccount, amount);
  } catch (err) {
    // Compensation: refund the source account so its balance is restored
    await refund(fromAccount, amount);

    // Re-surface the original error so the workflow reaches FAILED status.
    // Wrap in ApplicationFailure so Temporal records it cleanly.
    if (err instanceof ActivityFailure && err.cause instanceof ApplicationFailure) {
      throw ApplicationFailure.fromError(err.cause, { message: `Deposit failed; refund issued. Original: ${err.cause.message}` });
    }
    throw err;
  }
}

import { ApplicationFailure } from '@temporalio/activity';
import * as fs from 'fs';

const ACCOUNTS_FILE = '/workspace/accounts.json';

/**
 * Read the accounts JSON, apply a mutation, then write it back atomically.
 */
function mutateAccounts(fn: (accounts: Record<string, number>) => void): void {
  // Read
  const raw = fs.readFileSync(ACCOUNTS_FILE, 'utf8');
  const accounts: Record<string, number> = JSON.parse(raw);

  // Mutate
  fn(accounts);

  // Write (overwrite in place; this is single-process so no locking needed)
  fs.writeFileSync(ACCOUNTS_FILE, JSON.stringify(accounts, null, 2), 'utf8');
}

/**
 * Subtract `amount` from `accounts[account]`.
 */
export async function withdraw(account: string, amount: number): Promise<void> {
  console.log(`[activity] withdraw: account=${account} amount=${amount}`);
  mutateAccounts((accounts) => {
    const current = accounts[account] ?? 0;
    accounts[account] = current - amount;
  });
  console.log(`[activity] withdraw complete`);
}

/**
 * Add `amount` to `accounts[account]`.
 * If `account === "B_FAIL"`, throw a non-retryable error to simulate failure.
 */
export async function deposit(account: string, amount: number): Promise<void> {
  console.log(`[activity] deposit: account=${account} amount=${amount}`);

  if (account === 'B_FAIL') {
    // Non-retryable: mark as non-retryable so Temporal honours maximumAttempts=1
    throw ApplicationFailure.nonRetryable(
      `Deposit to account "${account}" is not allowed (simulated failure)`,
      'DepositFailed',
    );
  }

  mutateAccounts((accounts) => {
    const current = accounts[account] ?? 0;
    accounts[account] = current + amount;
  });
  console.log(`[activity] deposit complete`);
}

/**
 * Add `amount` back to `accounts[account]` — reverses a prior withdraw.
 */
export async function refund(account: string, amount: number): Promise<void> {
  console.log(`[activity] refund: account=${account} amount=${amount}`);
  mutateAccounts((accounts) => {
    const current = accounts[account] ?? 0;
    accounts[account] = current + amount;
  });
  console.log(`[activity] refund complete`);
}

import { Worker, NativeConnection } from '@temporalio/worker';
import * as activities from './activities';
import path from 'path';

async function main(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_ADDRESS, TEMPORAL_API_KEY, TEMPORAL_NAMESPACE',
    );
  }

  console.log(`[worker] Connecting to Temporal Cloud at ${address} (namespace: ${namespace})`);

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'saga-ts',
    // Point at the compiled workflow bundle directory
    workflowsPath: path.resolve(__dirname, 'workflows'),
    activities,
  });

  console.log('[worker] Worker started, polling task queue "saga-ts"...');
  await worker.run();
}

main().catch((err) => {
  console.error('[worker] Fatal error:', err);
  process.exit(1);
});

import { Connection, Client, WorkflowFailedError } from '@temporalio/client';
import { MoneyTransfer } from './workflows';

async function main(): Promise<void> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID;

  if (!address || !apiKey || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_ADDRESS, TEMPORAL_API_KEY, TEMPORAL_NAMESPACE',
    );
  }
  if (!runId) {
    throw new Error('Missing required environment variable: ZEALT_RUN_ID');
  }

  console.log(`[client] Connecting to Temporal Cloud at ${address} (namespace: ${namespace})`);

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({ connection, namespace });

  // -----------------------------------------------------------------------
  // Execution 1: Happy path — A → B, amount 30
  // -----------------------------------------------------------------------
  const okWorkflowId = `saga-ok-${runId}`;
  console.log(`\n[client] Starting workflow: ${okWorkflowId}`);

  const okHandle = await client.workflow.start(MoneyTransfer, {
    taskQueue: 'saga-ts',
    workflowId: okWorkflowId,
    args: [{ fromAccount: 'A', toAccount: 'B', amount: 30 }],
  });

  console.log(`[client] Waiting for ${okWorkflowId} to complete...`);
  await okHandle.result();
  console.log(`[client] ✅ ${okWorkflowId} — COMPLETED`);

  // -----------------------------------------------------------------------
  // Execution 2: Failure path — A → B_FAIL, amount 50 (deposit will fail)
  // -----------------------------------------------------------------------
  const failWorkflowId = `saga-fail-${runId}`;
  console.log(`\n[client] Starting workflow: ${failWorkflowId}`);

  const failHandle = await client.workflow.start(MoneyTransfer, {
    taskQueue: 'saga-ts',
    workflowId: failWorkflowId,
    args: [{ fromAccount: 'A', toAccount: 'B_FAIL', amount: 50 }],
  });

  console.log(`[client] Waiting for ${failWorkflowId} to reach terminal state...`);
  try {
    await failHandle.result();
    // If we somehow reach here, it means the workflow completed — that's unexpected.
    console.warn(`[client] ⚠️  ${failWorkflowId} completed unexpectedly (expected FAILED)`);
  } catch (err) {
    if (err instanceof WorkflowFailedError) {
      console.log(`[client] ✅ ${failWorkflowId} — FAILED as expected (compensation applied)`);
      console.log(`[client]    Failure reason: ${err.cause?.message ?? err.message}`);
    } else {
      // Unexpected error type — rethrow so the process exits non-zero
      throw err;
    }
  }

  // -----------------------------------------------------------------------
  // Summary
  // -----------------------------------------------------------------------
  const fs = await import('fs');
  const accounts = JSON.parse(fs.readFileSync('/workspace/accounts.json', 'utf8'));
  console.log('\n[client] ─── Final account balances ───────────────────────────────');
  console.log(`[client]   ${JSON.stringify(accounts, null, 2)}`);
  console.log('[client] ───────────────────────────────────────────────────────────');
  console.log('[client] Done. Exiting cleanly.');

  await connection.close();
}

main().catch((err) => {
  console.error('[client] Fatal error:', err);
  process.exit(1);
});

/**
 * run.ts — Orchestrates the worker and client in a single Node process.
 *
 * Strategy:
 *   1. Start the Worker (non-blocking — it runs on its own async loop).
 *   2. Run the Client script which executes both workflows and waits for
 *      their terminal states.
 *   3. Shut the worker down gracefully.
 *   4. Exit with code 0.
 */

